     7→	"fmt"
     8→	"net/http"
     9→	"strings"
    10→
    11→	"github.com/sentioxyz/changelogue/internal/models"
    12→)
    13→
    14→type slackConfig struct {
    15→	WebhookURL string `json:"webhook_url"`
    16→}
    17→
    18→// SlackSender sends notifications as Slack Block Kit messages via incoming webhook.
    19→type SlackSender struct {
    20→	Client *http.Client
    21→}
    22→
    23→// slackPayload is the Slack incoming webhook payload using Block Kit and/or attachments.
    24→type slackPayload struct {
    25→	Blocks      []slackBlock      `json:"blocks,omitempty"`
    26→	Attachments []slackAttachment `json:"attachments,omitempty"`
    27→}
    28→
    29→type slackBlock struct {
    30→	Type     string      `json:"type"`
    31→	Text     *slackText  `json:"text,omitempty"`
    32→	Fields   []slackText `json:"fields,omitempty"`
    33→	Elements []slackText `json:"elements,omitempty"`
    34→}
    35→
    36→type slackText struct {
    37→	Type string `json:"type"`
    38→	Text string `json:"text"`
    39→}
    40→
    41→// slackAttachment uses Slack's legacy attachment format which auto-collapses
    42→// long text with a "Show more" button.
    43→type slackAttachment struct {
    44→	Color     string   `json:"color,omitempty"`
    45→	Title     string   `json:"title,omitempty"`
    46→	TitleLink string   `json:"title_link,omitempty"`
    47→	Text      string   `json:"text,omitempty"`
    48→	MrkdwnIn  []string `json:"mrkdwn_in,omitempty"`
    49→}
    50→
    51→// urgencyEmoji returns an emoji indicator for the given urgency level.
    52→func urgencyEmoji(level string) string {
    53→	switch strings.ToUpper(strings.TrimSpace(level)) {
    54→	case "LOW":
    55→		return "🟢"
    56→	case "MEDIUM":
    57→		return "🟡"
    58→	case "HIGH":
    59→		return "🔴"
    60→	case "CRITICAL":
    61→		return "⚫"
    62→	default:
    63→		return "⚪"
    64→	}
    65→}
    66→
    67→// buildSemanticBlocks builds compact Slack Block Kit blocks from a SemanticReport.
    68→// For Critical/High urgency, includes the urgency reason. For Low/Medium, omits it.
    69→func buildSemanticBlocks(title string, report *models.SemanticReport, msg Notification) []slackBlock {
    70→	// Resolve urgency from new field or backward-compat risk_level
    71→	urgency := report.Urgency
    72→	if urgency == "" {
    73→		urgency = report.RiskLevel
    74→	}
    75→	urgencyReason := report.UrgencyReason
    76→	if urgencyReason == "" {
    77→		urgencyReason = report.RiskReason
    78→	}
    79→
    80→	// Header: "ProjectName vX.Y.Z — 🟢 Low Urgency"
    81→	headerText := title
    82→	if urgency != "" {
    83→		headerText = fmt.Sprintf("%s — %s %s Urgency", title, urgencyEmoji(urgency), urgency)
    84→	}
    85→	// Slack header max is 150 chars
    86→	if len(headerText) > 150 {
    87→		headerText = headerText[:147] + "..."
    88→	}
    89→
    90→	blocks := []slackBlock{
    91→		{Type: "header", Text: &slackText{Type: "plain_text", Text: headerText}},
    92→	}
    93→
    94→	// Urgency reason (only for Critical/High)
    95→	upperUrgency := strings.ToUpper(strings.TrimSpace(urgency))
    96→	if (upperUrgency == "CRITICAL" || upperUrgency == "HIGH") && urgencyReason != "" {
    97→		blocks = append(blocks, slackBlock{
    98→			Type: "section",
    99→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("⚠️ %s", urgencyReason)},
   100→		})
   101→	}
   102→
   103→	// Changelog summary
   104→	summary := report.ChangelogSummary
   105→	if summary == "" {
   106→		summary = report.Summary
   107→	}
   108→	if summary != "" {
   109→		blocks = append(blocks, slackBlock{
   110→			Type: "section",
   111→			Text: &slackText{Type: "mrkdwn", Text: summary},
   112→		})
   113→	}
   114→
   115→	// First download command only
   116→	if len(report.DownloadCommands) > 0 {
   117→		blocks = append(blocks, slackBlock{
   118→			Type: "section",
   119→			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("`%s`", report.DownloadCommands[0])},
   120→		})
   121→	}
   122→
   123→	// Footer context with source info and links
   124→	var footerParts []string
   125→	if msg.Provider != "" && msg.Repository != "" {
   126→		footerParts = append(footerParts, fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository))
   127→	}
   128→	if msg.SourceURL != "" {
   129→		footerParts = append(footerParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
   130→	}
   131→	if msg.ReleaseURL != "" {
   132→		footerParts = append(footerParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
   133→	}
   134→	if len(footerParts) > 0 {
   135→		blocks = append(blocks, slackBlock{
   136→			Type: "context",
   137→			Elements: []slackText{
   138→				{Type: "mrkdwn", Text: strings.Join(footerParts, "  |  ")},
   139→			},
   140→		})
   141→	}
   142→
   143→	return blocks
   144→}
   145→
   146→func (s *SlackSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
   147→	var cfg slackConfig
   148→	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
   149→		return fmt.Errorf("parse slack config: %w", err)
   150→	}
   151→
   152→	// Try to parse body as a SemanticReport for rich formatting.
   153→	var payload slackPayload
   154→	var report models.SemanticReport
   155→	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
   156→		payload.Blocks = buildSemanticBlocks(msg.Title, &report, msg)
   157→	} else {
   158→		// Fallback: source-level release notification.
   159→		// Use attachments for changelog so Slack auto-collapses long text
   160→		// with a "Show more" button.
   161→		var changelogText string
   162→		if fields, ok := parseRawBody(msg.Body); ok {
   163→			changelogText = fields.Changelog
   164→		}
   165→
   166→		if changelogText != "" {
   167→			// Build title link label
   168→			titleLabel := msg.Title
   169→			if msg.Repository != "" && msg.Provider != "" {
   170→				titleLabel = fmt.Sprintf("%s on %s", msg.Repository, ProviderLabel(msg.Provider))
   171→			}
   172→
   173→			// Build attachment text: title + version badge, then changelog
   174→			// converted to ASCII and wrapped in a code block. Slack
   175→			// auto-collapses long code blocks in attachments with a
   176→			// "Show more" button.
   177→			asciiChangelog := markdownToASCII(changelogText)
   178→			attachText := fmt.Sprintf("*%s* `%s`\n```%s```", msg.Title, msg.Version, asciiChangelog)
   179→
   180→			// Append links after the code block
   181→			var linkParts []string
   182→			if msg.SourceURL != "" {
   183→				linkParts = append(linkParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
   184→			}
   185→			if msg.ReleaseURL != "" {
   186→				linkParts = append(linkParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
   187→			}
   188→			if len(linkParts) > 0 {
   189→				attachText += "\n" + strings.Join(linkParts, "  |  ")
   190→			}
   191→
   192→			attachment := slackAttachment{
   193→				Color:    "#D3D3D3",
   194→				Title:    titleLabel,
   195→				Text:     attachText,
   196→				MrkdwnIn: []string{"text"},
   197→			}
   198→			if msg.SourceURL != "" {
   199→				attachment.TitleLink = msg.SourceURL
   200→			}
   201→			payload.Attachments = []slackAttachment{attachment}
   202→		} else {
   203→			// No changelog — show a clean version announcement instead of raw JSON.
   204→			headerText := msg.Title
   205→			if msg.Version != "" && msg.Title != msg.Version {
   206→				headerText = fmt.Sprintf("%s %s", msg.Title, msg.Version)
   207→			}
   208→			if len(headerText) > 150 {
   209→				headerText = headerText[:147] + "..."
   210→			}
   211→
   212→			blocks := []slackBlock{
   213→				{Type: "header", Text: &slackText{Type: "plain_text", Text: headerText}},
   214→			}
   215→
   216→			var linkParts []string
   217→			if msg.Provider != "" && msg.Repository != "" {
   218→				linkParts = append(linkParts, fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository))
   219→			}
   220→			if msg.SourceURL != "" {
   221→				linkParts = append(linkParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
   222→			}
   223→			if msg.ReleaseURL != "" {
   224→				linkParts = append(linkParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
   225→			}
   226→			if len(linkParts) > 0 {
   227→				blocks = append(blocks, slackBlock{
   228→					Type: "context",
   229→					Elements: []slackText{
   230→						{Type: "mrkdwn", Text: strings.Join(linkParts, "  |  ")},
   231→					},
   232→				})
   233→			}
   234→			payload.Blocks = blocks
   235→		}
   236→	}
   237→
   238→	body, err := json.Marshal(payload)
   239→	if err != nil {
   240→		return fmt.Errorf("marshal slack payload: %w", err)
   241→	}
   242→
   243→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
   244→	if err != nil {
   245→		return fmt.Errorf("create request: %w", err)
   246→	}
   247→	req.Header.Set("Content-Type", "application/json")
   248→
   249→	client := s.Client
   250→	if client == nil {
   251→		client = http.DefaultClient
   252→	}
   253→
   254→	resp, err := client.Do(req)
   255→	if err != nil {
   256→		return fmt.Errorf("send slack notification: %w", err)
   257→	}
   258→	defer resp.Body.Close()
   259→
   260→	if resp.StatusCode >= 400 {
   261→		return fmt.Errorf("slack returned status %d", resp.StatusCode)
   262→	}
   263→	return nil
   264→}
