   460→func (s *PgStore) CreateSubscriptionBatch(ctx context.Context, subs []models.Subscription) ([]models.Subscription, error) {
   461→	tx, err := s.pool.Begin(ctx)
   462→	if err != nil {
   463→		return nil, fmt.Errorf("begin tx: %w", err)
   464→	}
   465→	defer tx.Rollback(ctx)
   466→
   467→	var result []models.Subscription
   468→	for i := range subs {
   469→		sub := subs[i]
   470→		err := tx.QueryRow(ctx,
   471→			`INSERT INTO subscriptions (channel_id, type, source_id, project_id, version_filter)
   472→			 VALUES ($1, $2, $3, $4, $5)
   473→			 RETURNING id, created_at`,
   474→			sub.ChannelID, sub.Type, sub.SourceID, sub.ProjectID, sub.VersionFilter,
   475→		).Scan(&sub.ID, &sub.CreatedAt)
   476→		if err != nil {
   477→			return nil, fmt.Errorf("insert subscription %d: %w", i, err)
   478→		}
   479→		result = append(result, sub)
   480→	}
