    67→// buildSemanticBlocks builds compact Slack Block Kit blocks from a SemanticReport.
    68→// For Critical/High urgency, includes the urgency reason. For Low/Medium, omits it.
    69→func buildSemanticBlocks(title string, report *models.SemanticReport, msg Notification) []slackBlock {
