import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"strings"

	"github.com/sentioxyz/changelogue/internal/models"
)

type slackConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// SlackSender sends notifications as Slack Block Kit messages via incoming webhook.
type SlackSender struct {
	Client *http.Client
}

// slackPayload is the Slack incoming webhook payload using Block Kit and/or attachments.
type slackPayload struct {
	Blocks      []slackBlock      `json:"blocks,omitempty"`
	Attachments []slackAttachment `json:"attachments,omitempty"`
}

type slackBlock struct {
	Type     string      `json:"type"`
	Text     *slackText  `json:"text,omitempty"`
	Fields   []slackText `json:"fields,omitempty"`
	Elements []slackText `json:"elements,omitempty"`
}

type slackText struct {
	Type string `json:"type"`
	Text string `json:"text"`
}

// slackAttachment uses Slack's legacy attachment format which auto-collapses
// long text with a "Show more" button.
type slackAttachment struct {
	Color     string   `json:"color,omitempty"`
	Title     string   `json:"title,omitempty"`
	TitleLink string   `json:"title_link,omitempty"`
	Text      string   `json:"text,omitempty"`
	MrkdwnIn  []string `json:"mrkdwn_in,omitempty"`
}

// urgencyEmoji returns an emoji indicator for the given urgency level.
func urgencyEmoji(level string) string {
	switch strings.ToUpper(strings.TrimSpace(level)) {
	case "LOW":
		return "🟢"
	case "MEDIUM":
		return "🟡"
	case "HIGH":
		return "🔴"
	case "CRITICAL":
		return "⚫"
	default:
		return "⚪"
	}
}

// buildSemanticBlocks builds compact Slack Block Kit blocks from a SemanticReport.
// For Critical/High urgency, includes the urgency reason. For Low/Medium, omits it.
func buildSemanticBlocks(title string, report *models.SemanticReport, msg Notification) []slackBlock {
	// Resolve urgency from new field or backward-compat risk_level
	urgency := report.Urgency
	if urgency == "" {
		urgency = report.RiskLevel
	}
	urgencyReason := report.UrgencyReason
	if urgencyReason == "" {
		urgencyReason = report.RiskReason
	}

	// Header: "ProjectName vX.Y.Z — 🟢 Low Urgency"
	headerText := title
	if urgency != "" {
		headerText = fmt.Sprintf("%s — %s %s Urgency", title, urgencyEmoji(urgency), urgency)
	}
	// Slack header max is 150 chars
	if len(headerText) > 150 {
		headerText = headerText[:147] + "..."
	}

	blocks := []slackBlock{
		{Type: "header", Text: &slackText{Type: "plain_text", Text: headerText}},
	}

	// Urgency reason (only for Critical/High)
	upperUrgency := strings.ToUpper(strings.TrimSpace(urgency))
	if (upperUrgency == "CRITICAL" || upperUrgency == "HIGH") && urgencyReason != "" {
		blocks = append(blocks, slackBlock{
			Type: "section",
			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("⚠️ %s", urgencyReason)},
		})
	}

	// Changelog summary
	summary := report.ChangelogSummary
	if summary == "" {
		summary = report.Summary
	}
	if summary != "" {
		blocks = append(blocks, slackBlock{
			Type: "section",
			Text: &slackText{Type: "mrkdwn", Text: summary},
		})
	}

	// First download command only
	if len(report.DownloadCommands) > 0 {
		blocks = append(blocks, slackBlock{
			Type: "section",
			Text: &slackText{Type: "mrkdwn", Text: fmt.Sprintf("`%s`", report.DownloadCommands[0])},
		})
	}

	// Footer context with source info and links
	var footerParts []string
	if msg.Provider != "" && msg.Repository != "" {
		footerParts = append(footerParts, fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository))
	}
	if msg.SourceURL != "" {
		footerParts = append(footerParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
	}
	if msg.ReleaseURL != "" {
		footerParts = append(footerParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
	}
	if len(footerParts) > 0 {
		blocks = append(blocks, slackBlock{
			Type: "context",
			Elements: []slackText{
				{Type: "mrkdwn", Text: strings.Join(footerParts, "  |  ")},
			},
		})
	}

	return blocks
}

func (s *SlackSender) Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error {
	var cfg slackConfig
	if err := json.Unmarshal(ch.Config, &cfg); err != nil {
		return fmt.Errorf("parse slack config: %w", err)
	}

	// Try to parse body as a SemanticReport for rich formatting.
	var payload slackPayload
	var report models.SemanticReport
	if err := json.Unmarshal([]byte(msg.Body), &report); err == nil && report.Subject != "" {
		payload.Blocks = buildSemanticBlocks(msg.Title, &report, msg)
	} else {
		// Fallback: source-level release notification.
		// Use attachments for changelog so Slack auto-collapses long text
		// with a "Show more" button.
		var changelogText string
		if fields, ok := parseRawBody(msg.Body); ok {
			changelogText = fields.Changelog
		}

		if changelogText != "" {
			// Build title link label
			titleLabel := msg.Title
			if msg.Repository != "" && msg.Provider != "" {
				titleLabel = fmt.Sprintf("%s on %s", msg.Repository, ProviderLabel(msg.Provider))
			}

			// Build attachment text: title + version badge, then changelog
			// converted to ASCII and wrapped in a code block. Slack
			// auto-collapses long code blocks in attachments with a
			// "Show more" button.
			asciiChangelog := markdownToASCII(changelogText)
			attachText := fmt.Sprintf("*%s* `%s`\n```%s```", msg.Title, msg.Version, asciiChangelog)

			// Append links after the code block
			var linkParts []string
			if msg.SourceURL != "" {
				linkParts = append(linkParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
			}
			if msg.ReleaseURL != "" {
				linkParts = append(linkParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
			}
			if len(linkParts) > 0 {
				attachText += "\n" + strings.Join(linkParts, "  |  ")
			}

			attachment := slackAttachment{
				Color:    "#D3D3D3",
				Title:    titleLabel,
				Text:     attachText,
				MrkdwnIn: []string{"text"},
			}
			if msg.SourceURL != "" {
				attachment.TitleLink = msg.SourceURL
			}
			payload.Attachments = []slackAttachment{attachment}
		} else {
			// No changelog — show a clean version announcement instead of raw JSON.
			headerText := msg.Title
			if msg.Version != "" && msg.Title != msg.Version {
				headerText = fmt.Sprintf("%s %s", msg.Title, msg.Version)
			}
			if len(headerText) > 150 {
				headerText = headerText[:147] + "..."
			}

			blocks := []slackBlock{
				{Type: "header", Text: &slackText{Type: "plain_text", Text: headerText}},
			}

			var linkParts []string
			if msg.Provider != "" && msg.Repository != "" {
				linkParts = append(linkParts, fmt.Sprintf("%s · %s", ProviderLabel(msg.Provider), msg.Repository))
			}
			if msg.SourceURL != "" {
				linkParts = append(linkParts, fmt.Sprintf("<%s|View on %s>", msg.SourceURL, ProviderLabel(msg.Provider)))
			}
			if msg.ReleaseURL != "" {
				linkParts = append(linkParts, fmt.Sprintf("<%s|View in Changelogue>", msg.ReleaseURL))
			}
			if len(linkParts) > 0 {
				blocks = append(blocks, slackBlock{
					Type: "context",
					Elements: []slackText{
						{Type: "mrkdwn", Text: strings.Join(linkParts, "  |  ")},
					},
				})
			}
			payload.Blocks = blocks
		}
	}

	body, err := json.Marshal(payload)
	if err != nil {
		return fmt.Errorf("marshal slack payload: %w", err)
	}

	req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
	if err != nil {
		return fmt.Errorf("create request: %w", err)
	}
	req.Header.Set("Content-Type", "application/json")

	client := s.Client
	if client == nil {
		client = http.DefaultClient
	}

	resp, err := client.Do(req)
	if err != nil {
		return fmt.Errorf("send slack notification: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode >= 400 {
		return fmt.Errorf("slack returned status %d", resp.StatusCode)
	}
	return nil
}

package routing

import (
	"context"
	"encoding/json"
	"fmt"
	"net/url"
	"regexp"
	"strings"

	"github.com/sentioxyz/changelogue/internal/models"
)

// Notification is the payload sent through all notification channels.
type Notification struct {
	Title       string `json:"title"`
	Body        string `json:"body"`
	Version     string `json:"version"`
	ProjectName string `json:"project_name,omitempty"`
	Provider    string `json:"provider,omitempty"`
	Repository  string `json:"repository,omitempty"`
	ReleaseURL  string `json:"release_url,omitempty"`  // internal Changelogue link
	SourceURL   string `json:"source_url,omitempty"`   // upstream provider link
}

// Sender is the interface that all notification channel implementations must satisfy.
type Sender interface {
	Send(ctx context.Context, ch *models.NotificationChannel, msg Notification) error
}

// rawBodyFields contains the human-readable fields extracted from raw release JSON.
type rawBodyFields struct {
	Changelog  string
	ReleaseURL string
}

// parseRawBody extracts known fields from a raw JSON release body.
func parseRawBody(body string) (rawBodyFields, bool) {
	var raw map[string]interface{}
	if err := json.Unmarshal([]byte(body), &raw); err != nil {
		return rawBodyFields{}, false
	}

	fields := rawBodyFields{
		Changelog:  stringField(raw, "changelog"),
		ReleaseURL: stringField(raw, "release_url"),
	}

	if fields.Changelog == "" && fields.ReleaseURL == "" {
		return fields, false
	}
	return fields, true
}

func stringField(m map[string]interface{}, key string) string {
	v, _ := m[key].(string)
	return v
}

// ProviderURL builds the upstream release page URL for a given provider.
func ProviderURL(provider, repository, version string) string {
	switch strings.ToLower(provider) {
	case "github":
		return fmt.Sprintf("https://github.com/%s/releases/tag/%s", repository, version)
	case "dockerhub":
		return fmt.Sprintf("https://hub.docker.com/r/%s/tags?name=%s", repository, url.QueryEscape(version))
	case "ecr-public":
		return fmt.Sprintf("https://gallery.ecr.aws/%s", repository)
	case "gitlab":
		return fmt.Sprintf("https://gitlab.com/%s/-/releases/%s", repository, version)
	default:
		return ""
	}
}

// ProviderLabel returns a human-readable label for a provider.
func ProviderLabel(provider string) string {
	switch strings.ToLower(provider) {
	case "github":
		return "GitHub"
	case "dockerhub":
		return "Docker Hub"
	case "ecr-public":
		return "ECR Public"
	case "gitlab":
		return "GitLab"
	default:
		return provider
	}
}

// Regex patterns for markdown-to-ASCII conversion.
var (
	// GitHub PR/issue URLs → #NNN ( url )
	reGitHubPR = regexp.MustCompile(`https?://github\.com/([^/]+/[^/]+)/(pull|issues)/(\d+)`)
	// Markdown links [text](url) → text ( url )
	reMdLink = regexp.MustCompile(`\[([^\]]+)\]\(([^)]+)\)`)
	// Headings ## Text → dashed ASCII box
	reHeading = regexp.MustCompile(`(?m)^#{1,6}\s+(.+)$`)
	// Bold **text** and __text__
	reBoldStar = regexp.MustCompile(`\*\*(.+?)\*\*`)
	reBoldUnderscore = regexp.MustCompile(`__(.+?)__`)
	// Inline code `text`
	reInlineCode = regexp.MustCompile("`([^`]+)`")
	// HTML tags
	reHTML = regexp.MustCompile(`<[^>]+>`)
	// Images ![alt](url)
	reImage = regexp.MustCompile(`!\[([^\]]*)\]\([^)]+\)`)
)

// markdownToASCII converts GitHub-flavored Markdown into clean ASCII text
// suitable for display inside Slack/Discord code blocks.
func markdownToASCII(md string) string {
	s := md

	// Strip images first (before link processing)
	s = reImage.ReplaceAllString(s, "$1")

	// Convert GitHub PR/issue URLs to #NNN ( url )
	s = reGitHubPR.ReplaceAllString(s, "#$3 ( $0 )")

	// Convert markdown links [text](url) → text ( url )
	s = reMdLink.ReplaceAllString(s, "$1 ( $2 )")

	// Convert headings to ASCII art with dashes
	s = reHeading.ReplaceAllStringFunc(s, func(match string) string {
		parts := reHeading.FindStringSubmatch(match)
		title := strings.TrimSpace(parts[1])
		dashes := strings.Repeat("-", len(title))
		return dashes + "\n" + title + "\n" + dashes
	})

	// Strip bold markers
	s = reBoldStar.ReplaceAllString(s, "$1")
	s = reBoldUnderscore.ReplaceAllString(s, "$1")

	// Strip inline code backticks
	s = reInlineCode.ReplaceAllString(s, "$1")

	// Strip HTML tags
	s = reHTML.ReplaceAllString(s, "")

	// Collapse 3+ consecutive blank lines into 2
	reBlankLines := regexp.MustCompile(`\n{3,}`)
	s = reBlankLines.ReplaceAllString(s, "\n\n")

	return strings.TrimSpace(s)
}

