package routing

import (
	"context"
	"encoding/json"
	"net"
	"strings"
	"testing"

	"github.com/sentioxyz/changelogue/internal/models"
)

// mockSMTPServer starts a minimal SMTP server that captures the DATA payload.
// Returns the listener and a channel that receives the raw email message.
func mockSMTPServer(t *testing.T) (net.Listener, <-chan string) {
	t.Helper()
	ln, err := net.Listen("tcp", "127.0.0.1:0")
	if err != nil {
		t.Fatalf("listen: %v", err)
	}
	ch := make(chan string, 1)

	go func() {
		conn, err := ln.Accept()
		if err != nil {
			return
		}
		defer conn.Close()

		write := func(s string) { conn.Write([]byte(s + "\r\n")) }
		read := func() string {
			buf := make([]byte, 4096)
			n, _ := conn.Read(buf)
			return string(buf[:n])
		}

		write("220 localhost ESMTP")
		cmd := read()
		if strings.HasPrefix(cmd, "EHLO") {
			write("250-localhost")
			write("250 AUTH PLAIN LOGIN")
		}
		read() // AUTH
		write("235 Authentication successful")
		read() // MAIL FROM
		write("250 OK")
		read() // RCPT TO
		write("250 OK")

		// Handle additional RCPT TO commands
		for {
			line := read()
			if strings.HasPrefix(line, "RCPT TO") {
				write("250 OK")
				continue
			}
			if strings.HasPrefix(line, "DATA") {
				write("354 Start mail input")
				break
			}
		}

		// Read DATA until lone "."
		var data strings.Builder
		for {
			line := read()
			data.WriteString(line)
			if strings.Contains(line, "\r\n.\r\n") {
				break
			}
		}
		write("250 OK")
		ch <- data.String()

		read() // QUIT
		write("221 Bye")
	}()

	return ln, ch
}

func TestEmailSender_Send(t *testing.T) {
	ln, dataCh := mockSMTPServer(t)
	defer ln.Close()

	addr := ln.Addr().String()
	host, port, _ := net.SplitHostPort(addr)

	sender := &EmailSender{}
	ch := &models.NotificationChannel{
		Type: "email",
		Config: json.RawMessage(`{
			"smtp_host": "` + host + `",
			"smtp_port": ` + port + `,
			"username": "user",
			"password": "pass",
			"from_address": "noreply@example.com",
			"to_addresses": ["team@example.com"]
		}`),
	}
	msg := Notification{
		Title:      "geth",
		Body:       `{"changelog":"Security fixes and performance improvements"}`,
		Version:    "v1.14.0",
		Provider:   "github",
		Repository: "ethereum/go-ethereum",
		SourceURL:  "https://github.com/ethereum/go-ethereum/releases/tag/v1.14.0",
