	if data.Summary != "" {
		b.WriteString(data.Summary + "\n\n")
	}

	if data.Changelog != "" {
		b.WriteString(data.Changelog + "\n\n")
	}

	if data.DownloadCommand != "" {
		b.WriteString("  " + data.DownloadCommand + "\n\n")
	}

	if data.SourceURL != "" {
		b.WriteString("View on " + data.ProviderLabel + ": " + data.SourceURL + "\n")
	}
	if data.ReleaseURL != "" {
