		var data strings.Builder
		for {
			line := read()
			data.WriteString(line)
			if strings.Contains(line, "\r\n.\r\n") {
				break
			}
		}
		write("250 OK")
		ch <- data.String()

		read() // QUIT
		write("221 Bye")
	}()

	return ln, ch
}

